INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'overview', 'Overview > facts: IIT Kharagpur was the first IIT established in India in 1951.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'overview', 'Overview > facts: The campus is spread over 2100 acres, making it one of the largest IIT campuses in India.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'overview', 'Overview > facts: It has 21 Halls of Residence - 16 for boys and 5 for girls.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'overview', 'Overview > facts: Around 10,000 students study at IIT Kharagpur.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'overview', 'Overview > facts: The campus is self-contained with restaurants, banks, stadiums, gym, hospital, post office, market, swimming pool, and schools all within campus.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'overview', 'Overview > facts: The main building was established in 1951 and is the face of IIT Kharagpur.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'overview', 'Overview > facts: The campus has a 2.2 km road (called 2.2 road) that connects majority of the campus.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'overview', 'Overview > facts: Notable alumni include Sundar Pichai (CEO of Google), who graduated from the Metallurgical and Materials Engineering department.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'overview', 'Overview > facts: The campus was once a British detention camp, and the Nehru Museum preserves this history with a real aircraft on display.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'hostels_boys', 'Hostels Boys > first_year > facts: LBS Hall is one of the newer hostels, completed around 2010.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'hostels_boys', 'Hostels Boys > first_year > facts: The hostel has a night canteen that operates from 9:30 PM to 2:30 AM on the 2nd floor mess.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'hostels_boys', 'Hostels Boys > first_year > facts: There is a Nescafe shop beside the main gate open from 9 AM to 3 AM.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'hostels_boys', 'Hostels Boys > first_year > facts: LBS mess food is considered below average by many students, though the night canteen is rated well.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'hostels_boys', 'Hostels Boys > first_year: hostel: LBS Hall (Lal Bahadur Shastri Hall). sharing: 3-share per room. floors: 4. lift: False. allotment: Rooms are posted on the hostel building as soon as students complete JoSAA counselling and arrive at campus. No separate application needed.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'hostels_boys', 'Hostels Boys > second_year_onwards > hostels - name: MMM Hall (Pandit Madan Mohan Malviya Hall), sharing: 2-share, floors: 5-6, lift: True, capacity: 2000+ boarders, note: Largest hall in IIT Kharagpur. Completed in 2010. Mess food quality is debatable - some say it is one of the worst, others say it is decent.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'hostels_boys', 'Hostels Boys > second_year_onwards > hostels - name: LLR Hall (Lala Lajpat Rai Hall), sharing: 1-share (single), floors: 4, lift: False, note: Single rooms - considered lucky allotment.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'hostels_boys', 'Hostels Boys > second_year_onwards > hostels - name: Rajendra Prasad Hall (RP Hall), sharing: 3-share, floors: 4, lift: False, note: One of the first established halls in IIT Kharagpur. Has its own mess with decent food.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'hostels_boys', 'Hostels Boys > second_year_onwards > hostels - name: Radhakrishnan Hall, sharing: 3-share, floors: 4, lift: False');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'hostels_boys', 'Hostels Boys > second_year_onwards > hostels - name: Meghnad Saha Hall, sharing: 1-share (single), floors: 4, lift: False');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'hostels_boys', 'Hostels Boys > second_year_onwards > hostels - name: Patel Hall, note: Built in 1952, this is the first IIT hostel in all of India.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'hostels_boys', 'Hostels Boys > second_year_onwards > hostels - name: Azad Hall, note: Has good facilities and mess.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'hostels_boys', 'Hostels Boys > second_year_onwards: allotment: Random allotment through ERP system. Students have no choice in which hall they get.. continuity: Once allotted a hall in 2nd year, students stay in the same hall for 3rd and 4th year. Room number may change but hall remains same.. sharing_progression: 2nd year: as per hall default. 3rd year: may get upgraded to 2-sharing. 4th year: may get single room.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'hostels_girls', 'Hostels Girls > first_year: hostel: SNVH (Sister Niveditha Vidyarthi Hall). sharing: 3-share per room. floors: 4. lift: False');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'hostels_girls', 'Hostels Girls > second_year_onwards > hostels - name: Rani Laxmibai Hall, sharing: 2-share');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'hostels_girls', 'Hostels Girls > second_year_onwards > hostels - name: Mother Teresa Hall, sharing: 2-share, note: Located on 2.2 road.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'hostels_girls', 'Hostels Girls > second_year_onwards > hostels - name: Sarojini Naidu Hall, sharing: 2-share, note: Located near the clock tower on 2.2 road.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'hostels_girls', 'Hostels Girls > second_year_onwards: allotment: Random via ERP system, same as boys.. continuity: Same hall from 2nd to 4th year.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'hostel_common', 'Hostel Common: wifi: Unlimited. YouTube, Instagram, and all websites/apps work without restriction.. lan: Available in all hostels. Students need to buy their own LAN cable.. gate_timing: No separate hostel gate timing. Main college gate closes at 11 PM - cannot leave after 11 PM. If you left before 11 PM, the gate opens whenever you return. Gate opens at 5 AM.. no_curfew_note: There is no concept of in-time in hostels. Students can freely move around campus at night. The food court stays open until 4 AM.. delivery: Zomato and Swiggy deliveries are allowed. Delivery comes to the gate inside the college campus, just downstairs from the hostels.. furniture: Bed, table, chair, fan, cupboard, high-speed LAN port, lights, and adequate electricity ports are provided');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'hostel_common', 'Quantity varies by sharing type.. room_note: Rooms are spacious enough for 3 students in triple sharing. Storage space is limited - only a small cupboard for shared rooms.. mosquito_nets: Available in some hostels.. toilets: Western-style toilets available in newer hostels like LBS and MMM.. balcony: Some hostels have balconies with nice views.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'mess', 'Mess > specials: wednesday: Chicken served in almost all hostel messes.. friday: Some hostels serve biryani, others serve chicken.. sunday: Some hostels serve chicken, others serve biryani.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'mess', 'Mess: system: Each hostel has its own attached mess. No central mess.. schedule: Menu changes monthly. Mess committees actively take feedback from students.. cuisine: Both North Indian and South Indian cuisine. Vegetarian and non-vegetarian options available.. quality: Varies greatly by hostel. Generally rated 2-4 out of 5. Common complaint is inconsistency. LBS mess is considered below average, while some other halls like RP have decent food.. alternatives: Even if mess food is not great, there are many restaurants on campus - phone restaurants, heritage, PFC, and many more. Students from South India or North India can find food they are comfortable with.. night_canteen: Most hostels have night canteens that operate late into the night.. food_court: Stays open until 4 AM.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'food_outside', 'Food Outside > restaurants: Billoo''s - Famous for Punjabi food');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'food_outside', 'Food Outside > restaurants: Dreamland-Sahara');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'food_outside', 'Food Outside > restaurants: Hot Bite');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'food_outside', 'Food Outside > restaurants: Heritage');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'food_outside', 'Food Outside > restaurants: Phone - Popular restaurant');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'food_outside', 'Food Outside > restaurants: PFC (Fried chicken)');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'food_outside', 'Food Outside: tech_market: IIT Kharagpur has a self-sustained market called Tech Market within campus where students buy groceries, fruits, and daily necessities.. chains: Cafe Coffee Day, Baskin Robbins, and Subway are available on campus. Subway offers 30-40% discount for IIT students.. shiru_cafe: A Japanese-run cafe near Nalanda complex that serves free coffee, mango juice, and orange juice. They collect student data (roll number, email, phone) for marketing purposes in exchange.. tikka: Food stall near the back gate where you can get samosa, tiffins, noodles, fast food.. night_options: Night canteens in hostels, food court open till 4 AM.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'laundry', 'Laundry: method: Washing machines available on every floor in every hostel.. cost: Free to use.. iron: Available.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'sports_gym', 'Sports Gym: tata_sports_complex: Largest ground in IIT Kharagpur. Has 2 football grounds and 2 cricket grounds. Also has a running/jogging track. Training nets for cricket practice.. jnan_ghosh_stadium: Athletics stadium on par with national/international standards. Has synthetic running track.. gandhi_maidan: Hockey ground.. aquatic_center: Fully modernized swimming pool. Students can take membership.. hostel_gym: Every hostel has its own gym which is completely free. Open 24/7.. gymkhana_gym: Larger gym at Technology Students Gymkhana. Costs Rs 1000 per year. Available for both boys and girls. Timing: 7 AM to 11 AM, 6 PM to 9 PM.. other_sports: Cricket, football, basketball, tennis, badminton, athletics, karate, weightlifting (dedicated room).. sports_manageability: Sports and academics are easily manageable. Students wake up at 5-6 AM for morning sports or play in late afternoon after classes.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'transport', 'Transport: campus_bus: Each hostel has bus service that regularly transports students from hostels to department buildings.. cycling: Primary mode of transport. Almost all students buy cycles when they arrive. Essential due to 2100 acre campus size.. cycling_note: Make sure you learn cycling before coming to campus.. nearest_railway: Kharagpur Junction - 5 km from campus, 10-20 minutes. Auto Rs 100, Taxi Rs 200.. nearest_airport: Netaji Subhas Chandra Bose International Airport (CCU), Kolkata - 140 km, 2.5 hours by taxi.. to_kolkata: 120-130 km. Trains every 30 minutes from Kharagpur Junction to Howrah, taking 1.5-2.5 hours.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'academics', 'Academics: nalanda_complex: One of the biggest classroom complexes in India with capacity for over 30,000 students. Rooms equipped with centralized AC. Two types of classrooms: NR (Nalanda Rectangular) and NC (Nalanda Circular).. central_library: Largest technical library in Asia with over 3.1 lakh volumes including novels, publishing journals, textbooks, and reference books. Open to all students. New books added weekly.. departments: All major engineering departments available. Some unique departments: Ocean Engineering and Naval Architecture (only at IIT KGP and IIT Madras), Cryogenic Engineering (only at IIT KGP), Industrial Systems Engineering (only at IIT KGP).. attendance: 75% mandatory attendance policy was removed recently. Current policy is 0% attendance requirement');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'academics', 'However, internal marks increased from 20 to 40. Surprise tests and surprise attendance may count towards internals.. kalpana_chawla_cell: Kalpana Chawla Space Technology Cell - IIT Kharagpur''s direct point of contact with ISRO.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'fests', 'Fests: kshitij: Annual techno-management fest. One of the largest tech fests in Asia. Happens in January/February.. spring_fest: Annual social and cultural festival. First edition in 1960. 66th edition held in January 2025. Footfall of over 80,000 people. Events include dance, music, dramatics, photography, literature, quizzing, food fest, fine arts.. shaurya: Sports fest.. scale: Over 10,000 people from all over India attend. Guest sessions, events, workshops, competitions with prize money.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'elections', 'Elections > roles: Vice President (VP)');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'elections', 'Elections > roles: General Secretary of Sports and Games');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'elections', 'Elections > roles: General Secretary of Technology');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'elections', 'Elections > roles: General Secretary of Gymkhana');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'elections', 'Elections: eligibility: 3rd year ending students (entering 4th year) can stand for elections.. process: Students prepare proposals with complete workout plan including fund sources and permissions. They face a seniors panel and need to convince an audience of 6000-7000 people. The election process involves intense preparation and public speaking.. hall_elections: Each hall also has internal elections. Winning requires convincing students and building support.. maturity_note: The election process is known to bring remarkable maturity in students - a person who joined as a fresher in BTech develops significant leadership and public speaking skills by 3rd-4th year.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'medical', 'Medical: hospital: BC Roy Technology Hospital on campus. Available for all faculty, staff, and students.. access: Free for students.. location: Near the tech market.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'location_nearby', 'Location Nearby > weekend_trips - name: Kolkata, distance: 120-130 km, time: 1.5-2.5 hours by train, note: Most popular weekend destination. Trains every 30 minutes.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'location_nearby', 'Location Nearby > weekend_trips - name: Digha Beach, distance: 101 km, time: 1.5-2 hours by road');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'location_nearby', 'Location Nearby > long_trips - name: Puri Jagannath Temple, distance: 373 km, time: 5.5 hours by road/train');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'location_nearby', 'Location Nearby > long_trips - name: Varanasi, distance: 710 km, time: 13 hours by train');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'location_nearby', 'Location Nearby > long_trips - name: Darjeeling, distance: 650-670 km, time: 10 hours by road');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'campus_facilities', 'Campus Facilities: tech_market: Self-sustained market with barber shops, grocery stores, fruit/vegetable shops, sports shops, electronic shops, salons.. bc_roy_hospital: Campus hospital for students and faculty.. swimming_pool: Available with membership.. netaji_auditorium: Film screenings every week for students. Also hosts events, dance programs, musical nights.. kalidas_auditorium: Another auditorium for events, ceremonies, and fests.. technology_guest_house: Available for parents visiting campus and for alumni.. lakeside: Beautiful lake behind the gymkhana with an island connected by a bridge. Popular spot for birthday celebrations.. robotics_room: Dedicated facility for robotics enthusiasts.. vinod_gupta_school: School of Management for MBA, gifted by alumni Vinod Gupta');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'campus_facilities', 'Advanced architecture.. nehru_museum: Former British detention camp converted to museum. Has a real aircraft on display. Must-visit with parents.. rajiv_gandhi_law_school: Law school within IIT Kharagpur campus.. banks_atms: Available on campus.. post_office: Available on campus.. railway_reservation: Counter available on campus.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'culture_vibe', 'Culture Vibe: overall: IIT Kharagpur is a mixture of everything - academics, sports, library, fests, hall activities, and variety activities.. clubs: Robotics, coding, dance, music, dramatics, and many more technical and cultural clubs.. night_life: No hostel curfew. Food court open till 4 AM. Birthday celebrations at lakeside at midnight.. language: Mix of Hindi and English. Bengali is local language but Hindi/English is sufficient.. senior_junior: Strong hall culture and bonding. Elections and hall activities bring students together.');